import UIKit
struct Sentence: Codable {
    let subject: String
    let verb: String
    let object: String
    let extraWords: String
    enum CodingKeys: String, CodingKey {
        case subject
        case verb
        case object
        case extraWords = "extra_words"
    }
}
class ViewController: UIViewController, UITableViewDataSource {
    @IBOutlet weak var tableView: UITableView!
    var sentences = [Sentence]()
    override func viewDidLoad() {
        super.viewDidLoad()
        guard let url = Bundle.main.url(forResource: "sentences", withExtension: "json") else { return }
        do {
            let data = try Data(contentsOf: url)
            sentences = try JSONDecoder().decode([Sentence].self, from: data)
        } catch {
            print(error)
        }
        tableView.dataSource = self
        tableView.reloadData()
    }
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return sentences.count
    }
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "cell", for: indexPath)
        let sentence = sentences[indexPath.row]
        cell.textLabel?.text = "\(sentence.subject) \(sentence.verb) \(sentence.object) \(sentence.extraWords)"
        return cell
    }
    func filterSentences() {
