What are some advanced optimization techniques that can be used to enhance website performance, in addition to breaking down large chunks of data, using caching systems, and utilizing compression algorithms? Can you provide some sample Java code that implements these techniques?
For example, one technique could be to implement lazy loading for images and other media files, so that they are only loaded when they are needed. Another technique could be to use asynchronous processing for certain tasks, such as database queries, to avoid blocking the main thread and improve overall performance. Can you provide some Java code snippets that demonstrate these techniques?

### Response:
Sure, here are some Java code snippets that demonstrate the techniques you mentioned:
1. Lazy Loading for Images and Other Media Files:
```
// HTML code
<img data-src="path/to/image.jpg" class="lazyload" />
// JavaScript code
document.addEventListener("DOMContentLoaded", function() {
  var lazyImages = [].slice.call(document.querySelectorAll("img.lazyload"));
  if ("IntersectionObserver" in window) {
    var lazyImageObserver = new IntersectionObserver(function(entries, observer) {
      entries.forEach(function(entry) {
        if (entry.isIntersecting) {
          var lazyImage = entry.target;
          lazyImage.src = lazyImage.dataset.src;
          lazyImage.classList.remove("lazyload");
          lazyImageObserver.unobserve(lazyImage);
        }
      });
    });
    lazyImages.forEach(function(lazyImage) {
      lazyImageObserver.observe(lazyImage);
    });
  } else {
    // Fallback for browsers that don't support IntersectionObserver
    var lazyLoad = function() {
      lazyImages.forEach(function(lazyImage) {
        if (lazyImage.getBoundingClientRect().top <= window.innerHeight && lazyImage.getBoundingClientRect().bottom >= 0 && getComputedStyle(lazyImage).display !== "none") {
          lazyImage.src = lazyImage.dataset.src;
          lazyImage.classList.remove("lazyload");
          lazyImages = lazyImages.filter(function(image) {
            return image !== lazyImage;
          });
          if (lazyImages.length === 0) {
            document.removeEventListener("scroll", lazyLoad);
            window.removeEventListener("resize", lazyLoad);
            window.removeEventListener("orientationchange", lazyLoad);
          }
        }
      });
    };
    document.addEventListener("scroll", lazyLoad);
    window.addEventListener("resize", lazyLoad);
    window.addEventListener("orientationchange", lazyLoad);
  }
});
```
